// BaseWithContext é uma função auxiliar que busca o email do contexto e renderiza o layout
func BaseWithContext(ctx goContext.Context, pageTitle string, content templ.Component) templ.Component {
	// Get user email from context
	userEmail, err := appcontext.GetUserEmail(ctx)
	if err != nil {
		// Use default email if not available
		userEmail = "user@example.com"
	}

	// Retornar o componente que já inclui o email
	return BaseWithContentAndEmail(pageTitle, userEmail, content)
}

